RuleSet.GenFile:
-- -- @(#) $GenPackageDir$/$GenFileName$ $MssDoubleDashScriptLicense$ alter session set plsql_warnings = 'ENABLE:ALL'; /
create or replace procedure $lower DbSchemaName$.$sp_read_dbtablename_cc_all$( retCursor out sys_refcursor,$implOracleSPStandardArgs$ ) authid definer is$switch SecScope None empty System empty Cluster implOracleSPReadTableDeclPermFlag Tenant implOracleSPReadTableDeclPermFlag default error$ begin$poptop Table switch TableName Cluster empty Tenant empty SecUser empty default implOracleSPReadEnforceSec$$switch SecScope None implOracleSPReadTableCCAllRetSelectSystem System implOracleSPReadTableCCAllRetSelectSystem Cluster implOracleSPReadTableCCAllRetSelectRestrictCluster Tenant implOracleSPReadTableCCAllRetSelectRestrictTenant default error$ end $sp_read_dbtablename_cc_all$; /
show errors procedure $lower DbSchemaName$.$sp_read_dbtablename_cc_all$;

RuleSet.GenRule:
if( isSystemUser = 1 )
then
	open retCursor for select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ $lower ClassCode$$switch HasSuperClassRelation yes implOracleClassCodeJoinSuperTable default empty$
	order by ClassCode asc;
else
	open retCursor for select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ $lower ClassCode$$switch HasSuperClassRelation yes implOracleClassCodeJoinSuperTable default empty$$implOracleSPReadTableRetSelectWhereRestrictCluster$;
end if;

if( isSystemUser = 1 )
then
	open retCursor for select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ $lower ClassCode$$switch HasSuperClassRelation yes implOracleClassCodeJoinSuperTable default empty$
	order by ClassCode asc;
else
	open retCursor for select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ $lower ClassCode$$switch HasSuperClassRelation yes implOracleClassCodeJoinSuperTable default empty$$implOracleSPReadTableRetSelectWhereRestrictTenant$;
end if;
